### Create Line Chart with Multiple Data Series in Recharts

Source: https://context7.com/recharts/recharts/llms.txt

Build a multi-line chart component displaying sales, expenses, and profit trends over months. The LineChart uses ResponsiveContainer for automatic sizing, CartesianGrid for background grid, and multiple Line components with different stroke colors and styles. Includes interactive tooltips, legends, and custom dot styling.

```jsx
import React from 'react';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer } from 'recharts';

const data = [
  { name: 'Jan', sales: 4000, expenses: 2400, profit: 1600 },
  { name: 'Feb', sales: 3000, expenses: 1398, profit: 1602 },
  { name: 'Mar', sales: 2000, expenses: 9800, profit: -7800 },
  { name: 'Apr', sales: 2780, expenses: 3908, profit: -1128 },
  { name: 'May', sales: 1890, expenses: 4800, profit: -2910 },
  { name: 'Jun', sales: 2390, expenses: 3800, profit: -1410 },
  { name: 'Jul', sales: 3490, expenses: 4300, profit: -810 }
];

function LineChartExample() {
  return (
    <ResponsiveContainer width="100%" height={400}>
      <LineChart
        data={data}
        margin={{ top: 5, right: 30, left: 20, bottom: 5 }}
      >
        <CartesianGrid strokeDasharray="3 3" />
        <XAxis dataKey="name" />
        <YAxis />
        <Tooltip />
        <Legend />
        <Line
          type="monotone"
          dataKey="sales"
          stroke="#8884d8"
          strokeWidth={2}
          activeDot={{ r: 8 }}
          dot={{ r: 4 }}
        />
        <Line
          type="monotone"
          dataKey="expenses"
          stroke="#82ca9d"
          strokeWidth={2}
        />
        <Line
          type="monotone"
          dataKey="profit"
          stroke="#ff7300"
          strokeDasharray="5 5"
        />
      </LineChart>
    </ResponsiveContainer>
  );
}

export default LineChartExample;
```

