### Implement Responsive Charts with Recharts ResponsiveContainer in React

Source: https://context7.com/recharts/recharts/llms.txt

This React component illustrates the use of Recharts' ResponsiveContainer to create charts that automatically adapt to their parent container's size. It shows examples of percentage-based sizing, aspect ratio constraints, and how to use the debounce and onResize props for performance optimization and callback functionality. The ResponsiveContainer wraps LineChart instances, ensuring fluid and dynamic chart layouts.

```jsx
import React from 'react';
import { ResponsiveContainer, LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip } from 'recharts';

const data = [
  { name: 'Page A', uv: 4000 },
  { name: 'Page B', uv: 3000 },
  { name: 'Page C', uv: 2000 },
  { name: 'Page D', uv: 2780 },
  { name: 'Page E', uv: 1890 },
];

function ResponsiveExample() {
  return (
    <div style={{ width: '100%', height: '100%' }}>
      {/* Percentage-based sizing */}
      <ResponsiveContainer width="100%" height={300}>
        <LineChart data={data}>
          <CartesianGrid strokeDasharray="3 3" />
          <XAxis dataKey="name" />
          <YAxis />
          <Tooltip />
          <Line type="monotone" dataKey="uv" stroke="#8884d8" />
        </LineChart>
      </ResponsiveContainer>

      {/* Aspect ratio constraint */}
      <ResponsiveContainer width="100%" aspect={2}>
        <LineChart data={data}>
          <CartesianGrid strokeDasharray="3 3" />
          <XAxis dataKey="name" />
          <YAxis />
          <Tooltip />
          <Line type="monotone" dataKey="uv" stroke="#82ca9d" />
        </LineChart>
      </ResponsiveContainer>

      {/* With resize callback and debounce */}
      <ResponsiveContainer
        width="100%"
        height={400}
        debounce={300}
        onResize={(width, height) => console.log(`Chart resized to ${width}x${height}`)}
      >
        <LineChart data={data}>
          <CartesianGrid strokeDasharray="3 3" />
          <XAxis dataKey="name" />
          <YAxis />
          <Tooltip />
          <Line type="monotone" dataKey="uv" stroke="#ff7300" />
        </LineChart>
      </ResponsiveContainer>
    </div>
  );
}

export default ResponsiveExample;
```

